	return (
		<>
			<CssBaseline />
				<Box
					display='flex'
					height={'100vh'}
					width={'100wh'}
					sx={{
						alignItems: 'center',
						backgroundColor: 'grey',
						backgroundImage: `linear-gradient(rgba(255,255,255,0.5), rgba(255,255,255,0.5)), url(${image})`,
						backgroundSize: 'cover',
						backgroundRepeat: 'no-repeat',
						backgroundPosition: 'relative',
					}}
				>
					<Box flex='1' width={100} sx={{ marginLeft: 5, marginRight: 5, marginTop: 3 }}>
						<Typography variant='h1' sx={{ textAlign: 'center', fontSize: 50, fontWeight: 50 }}>
							Title Here
						</Typography>
						<Typography variant='h2' sx={{ textAlign: 'center', fontSize: 25, fontWeight: 20 }}>
							Subtitle here
						</Typography>
						<Button onClick={() => navigate('/collections')} color='inherit'>Collections</Button>
					</Box>
				</Box>
		</>
	)
}

export default Hero;
